VALUES
  ('cpa-moex-01521', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '新一公司將直接原料加工製造成機車使用的零組件。下列為該公司本年度7月及8月的營運相關資 料： 7月    8月 產出數量（個）    56,000 50,000 直接原料用量（磅數）    10,000 9,000 直接原料成本（每磅）    $10 $8 直接人工小時    3,000 2,800 直接人工工資（每小時）    $60 $75 新一公司7月份之全部要素生產力（total factor productivity）為何？', '["5.6", "0.56", "0.2", "0.18"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01522', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '台一公司生產餅乾和糖果，98年度營運資料如下： 產品  預計  實際 種類  單位售價 單位成本  銷售量  單位售價 單位成本 銷售量 餅乾  $30 $20  6,000 $32 $22 6,400 糖果  20 14  8,000 22 15 7,000', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01523', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '年度，餅乾與糖果預計分攤的固定成本分別為$30,000 與$32,000，實際分攤之固定成本則為 $38,400與$42,000。台一公司98年度之邊際貢獻價格差異為多少？', '["$4,000有利", "$7,000有利", "$23,400有利", "$27,400有利"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 98, "answer_corrected": false, "flags": ["answer_missing"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01524', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '龍山公司是一個跨國公司，其生產據點設在稅率較低的國家，銷售據點設在稅率較高的國家。從節 稅的目的而言，龍山公司應如何處理？', '["停止在低稅率國家生產工作", "停止在高稅率國家行銷工作", "當其生產據點銷售產品至其銷售據點時，採用低轉撥價格", "當其生產據點銷售產品至其銷售據點時，採用高轉撥價格"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01525', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '向興公司的A事業部生產B事業部所需的零件，製造成本如下：每單位之直接材料、直接人工、變 動製造費用、固定製造費用（以實際產能250,000單位計算）分別為$30、$8、$10與$12。固定銷售 與管理成本為$1,200,000，變動銷售費用每單位$4。A事業部每年可以生產250,000單位，該零件每 單位可以$90賣到外部市場，預計下年度可賣200,000單位。如果該零件賣給B事業部，可以省去變 動銷售費用。B事業部可以每單位$80從外部市場買到相同的零件，預計下年度需要40,000單位。 如果B事業部下年度需要的40,000單位，都以每單位$56向A事業部購買，則公司淨利影響為何？', '["增加$1,280,000", "減少$1,280,000", "增加$1,380,000", "減少$1,380,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01526', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '下列各項有關產品別獲利分析之敘述，何者錯誤？', '["產品別獲利分析應包含與個別客戶有關之銷售與行銷成本分析，故產品別獲利分析即為客戶別獲 利分析", "作業基礎成本制有助於企業計算其產品成本", "分析評估企業各項產品產銷作業活動之附加價值乃產品別獲利分析之主要目的之一", "產品別獲利分析有助於企業產品產銷組合決策之作成"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01527', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '會計部門正在計算客戶別之銷售報酬率（return on sales）。相關資料列示如下： 客戶甲    客戶乙    客戶丙 銷貨    $500,000    $1,200,000    $800,000 邊際貢獻    160,000    360,000    280,000 營業成本    (90,000)    (410,000) (180,000) 若營業成本為固定成本，為使客戶乙之銷貨報酬率不為負，則對其銷貨額應增加多少？', '["$166,667", "$585,714", "$614,286", "$1,366,667"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01528', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '某公司由於手動照相機事業部長久虧損，因而打算關閉這個事業部。這個事業部上一季的相關資訊 如下： 銷貨（1,000台）    $1,000,000 製造成本 直接材料    500,000 直接人工（每小時$50）    200,000 製造費用    400,000 營業損失    ($100,000) 製造費用成本其中70%屬於變動製造費用，其餘30%為該事業部所屬的特殊設備的折舊費用，該設 備無法出售給他人。如果這個事業部被關閉，營業利益將有何影響？', '["營業利益增加$100,000", "營業利益減少$20,000", "營業利益增加$180,000", "營業利益減少$120,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01529', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '太陽公司是電視製造商，目前公司一舊款產品的邊際貢獻總額為4,000萬元，公司管理當局擬開發新 款的電視來取代此舊款電視，據公司高層估計成功的機率為 60%，成功後新款電視的總邊際貢獻為 10,000萬元，若失敗，則總邊際貢獻只有800萬元。試問完美資訊（perfect information）的價值為多 少？', '["1,280萬元", "6,000萬元", "6,320萬元", "7,600萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01530', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '和平公司採用現購政策，一年對A產品的需求量為60,000件。若每月初採購5,000件，每件售價 $100；若年初一次採購60,000件，則每件價格為$95。若和平公司的年投資報酬率為8%，則二種採 購方案的資金機會成本差異數為：', '["$208,000", "$228,000", "$416,000", "$456,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
